import axios from 'axios';

require('dotenv').config();

let client: any;

/**
 * Axios is not compatible with an HTTPS proxy that needs to be contacted
 * with HTTP. So we'll deactivate axios proxy and handle proxying manually
 * by using a custom proxified HTTPS agent whenever we need to.
 * See https-agent-for-url.ts for implementation details.
 */

client = axios.create({
  proxy: false,
});

client.defaults.withCredentials = true;
client.defaults.maxRedirects = 0;

if (process.env.E2E_TOKEN_FETCHER_NOACS) {
  /**
   * Here I would have liked to use axios-cookiejar-support,
   * but since v2.x it does not support agents other than https.Agent.
   *
   * So there is no way I can set options like keepAlive: true
   * when using axios-cookiejar-support, or use agents with proxy.
   *
   * So we will handle the cookie jar directly in the agents.
   * See https-agents.ts for implementation details.
   *
   * Note that at this point, this mode does not seem to be working
   * at RNTBCI, with 401 errors being reported at the idp2 login step.
   */
} else {
  /**
   * https://www.npmjs.com/package/axios-cookiejar-support
   *
   * This will only work with v1.x of axios-cookiejar-support
   */

  const axiosCookieJarSupport = require('axios-cookiejar-support').default;
  const tough = require('tough-cookie');

  axiosCookieJarSupport(client);
  client.defaults.jar = new tough.CookieJar();
}

export { client };
